(()=>{WF.registerEffect("scale-reveal",function(r){var t=[],n=gsap.matchMedia();n.add({isDesktop:"(min-width: 768px)",isMobile:"(max-width: 767px)",reduceMotion:"(prefers-reduced-motion: reduce)"},function(e){var i=e.conditions;if(i.reduceMotion||i.isMobile){r.forEach(function(a){gsap.set(a,{scale:1,borderRadius:"0px"})});return}r.forEach(function(a){var s=parseFloat(a.dataset.animateScale)||.85,o=parseFloat(a.dataset.animateRadius)||24,c=parseFloat(a.dataset.animateDistance)||400;t.push(gsap.fromTo(a,{scale:s,borderRadius:o+"px"},{scale:1,borderRadius:"0px",ease:"none",transformOrigin:"center center",scrollTrigger:{trigger:a,start:"top top",end:"+="+c,pin:!0,scrub:1,invalidateOnRefresh:!0}}))})}),WF.onCleanup(function(){t.forEach(function(e){e.kill()})})});})();
